import{_ as e,o as l,c as t,aw as i}from"./chunks/framework.DLufY-ao.js";const m=JSON.parse('{"title":"Тег Meta Viewport","description":"","frontmatter":{},"headers":[],"relativePath":"wiki/dev-commit/layout/layout/adaptive/meta-viewport.md","filePath":"wiki/dev-commit/layout/layout/adaptive/meta-viewport.md"}'),o={name:"wiki/dev-commit/layout/layout/adaptive/meta-viewport.md"};function s(n,a,c,r,d,p){return l(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="тег-meta-viewport" tabindex="-1">Тег Meta Viewport <a class="header-anchor" href="#тег-meta-viewport" aria-label="Permalink to &quot;Тег Meta Viewport&quot;">​</a></h1><div class="info custom-block"><p class="custom-block-title">INFO</p><ul><li><a href="https://itchief.ru/lessons/html-and-css/meta-viewport-how-it-works" target="_blank" rel="noreferrer">https://itchief.ru/lessons/html-and-css/meta-viewport-how-it-works</a> - Статья</li><li><a href="https://www.mydevice.io/" target="_blank" rel="noreferrer">https://www.mydevice.io/</a></li></ul></div><h2 id="объявление" tabindex="-1">Объявление <a class="header-anchor" href="#объявление" aria-label="Permalink to &quot;Объявление&quot;">​</a></h2><div class="language-html"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki one-light vp-code" tabindex="0"><code><span class="line"><span style="color:#383A42;">&lt;</span><span style="color:#E45649;">meta</span></span>\n<span class="line"><span style="color:#986801;">  name</span><span style="color:#383A42;">=</span><span style="color:#50A14F;">&quot;viewport&quot;</span></span>\n<span class="line"><span style="color:#986801;">  content</span><span style="color:#383A42;">=</span><span style="color:#50A14F;">&quot;</span></span>\n<span class="line"><span style="color:#50A14F;">    width=device-width,</span></span>\n<span class="line"><span style="color:#50A14F;">    initial-scale=1.0,</span></span>\n<span class="line"><span style="color:#50A14F;">    minimal-scale=1.0,</span></span>\n<span class="line"><span style="color:#50A14F;">    maximal-scale=1.0,</span></span>\n<span class="line"><span style="color:#50A14F;">    user-scalable=no</span></span>\n<span class="line"><span style="color:#50A14F;">  &quot;</span></span>\n<span class="line"><span style="color:#383A42;">/&gt;</span></span></code></pre></div><h2 id="параметры-атрибута-name" tabindex="-1">Параметры атрибута name <a class="header-anchor" href="#параметры-атрибута-name" aria-label="Permalink to &quot;Параметры атрибута name&quot;">​</a></h2><h3 id="name-viewport" tabindex="-1"><code>name=&quot;viewport&quot;</code> <a class="header-anchor" href="#name-viewport" aria-label="Permalink to &quot;`name=&quot;viewport&quot;`&quot;">​</a></h3><ul><li><code>Viewport</code> - видимая пользователю область страницы (то, что может увидеть пользователь, не прибегая к прокрутке)</li><li><code>Метатег Viewport</code> - был разработан компанией Apple для того, чтобы указывать браузерам на то, в каком масштабе необходимо отображать пользователю видимую область веб-страницы. Он предназначен для того, чтобы веб-страницы отображались корректно на смартфонах, планшетах и других устройствах с высокой плотностью пикселей (&gt; 200 ppi)</li></ul><h2 id="параметры-атрибута-content" tabindex="-1">Параметры атрибута content <a class="header-anchor" href="#параметры-атрибута-content" aria-label="Permalink to &quot;Параметры атрибута content&quot;">​</a></h2><h3 id="width-device-width" tabindex="-1"><code>width=device-width</code> <a class="header-anchor" href="#width-device-width" aria-label="Permalink to &quot;`width=device-width`&quot;">​</a></h3><ul><li><code>width=device-width</code> - соотношение ширины видимой области веб-страницы с CSS шириной устройства</li><li><code>width=device-width</code> отвечает за то, чтобы ширина видимой области веб-страницы равнялась CSS ширине устройству (device-width). CSS ширина устройства - это не физическое разрешение экрана. Это некоторая величина независящая от разрешения экрана. Она предназначена для того, чтобы мобильный адаптивный дизайн сайта отображался на всех устройствах одинаково независимо от их плотности пикселей экрана</li><li>Н-р, смартфон iPhone 4 с физическим разрешением 640x960 имеет CSS разрешение 320x480. Это означает то, что сайт с метатегом viewport (width=device-width) на этом устройстве будет выглядеть так как будто бы это устройство имеет разрешение 320x480 (в данном случае вместо device-width будет подставляться значение 320px). Т.е. на один CSS пиксель будет приходиться 4 физических пикселя (2 по горизонтали и 2 по вертикали)</li></ul><h3 id="initial-scale-1-0" tabindex="-1"><code>initial-scale=1.0</code> <a class="header-anchor" href="#initial-scale-1-0" aria-label="Permalink to &quot;`initial-scale=1.0`&quot;">​</a></h3><ul><li><code>initial-scale=1.0</code> - первоначальный масштаб веб-страницы (1.0 == 100%)</li></ul><h3 id="minimal-scale-1-0" tabindex="-1"><code>minimal-scale=1.0</code> <a class="header-anchor" href="#minimal-scale-1-0" aria-label="Permalink to &quot;`minimal-scale=1.0`&quot;">​</a></h3><ul><li><code>minimal-scale=1.0</code> - задаёт минимальный масштаб</li></ul><h3 id="maximal-scale-1-0" tabindex="-1"><code>maximal-scale=1.0</code> <a class="header-anchor" href="#maximal-scale-1-0" aria-label="Permalink to &quot;`maximal-scale=1.0`&quot;">​</a></h3><ul><li><code>maximal-scale=1.0</code> - задаёт максимальный масштаб</li></ul><h3 id="user-scalable-no" tabindex="-1"><code>user-scalable=no</code> <a class="header-anchor" href="#user-scalable-no" aria-label="Permalink to &quot;`user-scalable=no`&quot;">​</a></h3><ul><li><code>user-scalable=no</code> - указывает, может ли пользователь управлять масштабом</li></ul>',18)])])}const u=e(o,[["render",s]]);export{m as __pageData,u as default};
